import time, math
from dataclasses import dataclass, field

@dataclass
class Memory:
    text: str
    importance: float          # 1..10, assigned by an LLM at insert time
    embedding: list
    created: float = field(default_factory=time.time)
    last_access: float = field(default_factory=time.time)

class MemoryStream:
    def __init__(self, decay=0.995):
        self.mems = []
        self.decay = decay

    def add(self, text, importance, embedding):
        self.mems.append(Memory(text, importance, embedding))

    def _recency(self, m, now):
        hours = (now - m.last_access) / 3600.0
        return self.decay ** hours

    def retrieve(self, query_emb, k=5, a_r=1.0, a_i=1.0, a_v=1.0):
        now = time.time()
        scored = []
        for m in self.mems:
            rec = self._recency(m, now)
            imp = m.importance / 10.0
            rel = cosine(query_emb, m.embedding)
            scored.append((a_r*rec + a_i*imp + a_v*rel, m))
        scored.sort(key=lambda x: x[0], reverse=True)
        top = [m for _, m in scored[:k]]
        for m in top:
            m.last_access = now       # accessing refreshes recency
        return top

def cosine(a, b):
    dot = sum(x*y for x, y in zip(a, b))
    na = math.sqrt(sum(x*x for x in a)); nb = math.sqrt(sum(y*y for y in b))
    return dot / (na*nb + 1e-9)
